package ccxtpro
import ccxt "github.com/ccxt/ccxt/go/v4"
type Mudrex struct {
   *MudrexCore
   Core *MudrexCore
   exchangeTyped *ccxt.Mudrex
}

func NewMudrex(userConfig map[string]any) *Mudrex {
   p := NewMudrexCore()
   p.Init(userConfig)
   return &Mudrex{
       MudrexCore: p,
       Core:  p,
       exchangeTyped: ccxt.NewMudrexFromCore(p.base),
   }
}


